+fn build_corrected_production_seam(occurrence: &SeamOccurrence) -> CorrectedProductionSeam {
+    CorrectedProductionSeam {
+        seam_id: format!(
+            "{}:{}:{}",
+            occurrence.file_path, occurrence.line_number, occurrence.kind
+        ),
